#' Logistic Regression
#'
#' Logistic Regression with feature selection. Note that cross-validation fold 
#' partitioning uses a hardcoded random seed (42) for reproducibility.
#' @param data .
#' @param dep .
#' @param covs .
#' @param factors .
#' @param group .
#' @param selgroup .
#' @param method .
#' @param elastic_alpha .
#' @param lasso_penalty .
#' @param partition .
#' @param val_split .
#' @param cv_folds .
#' @param cv_repeats .
#' @param show_formula .
#' @param show_roc .
#' @param roc_x .
#' @param roc_unit .
#' @param palBrewer .
#' @param seed .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$text} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$infoTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coeffTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$formulaHtml} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$rocPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$predClass} \tab \tab \tab \tab \tab an output \cr
#'   \code{results$predProb} \tab \tab \tab \tab \tab an output \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$infoTable$asDF}
#'
#' \code{as.data.frame(results$infoTable)}
#'
#' @export
mLR <- function(
    data,
    dep,
    covs,
    factors,
    group,
    selgroup,
    method = "manual",
    elastic_alpha = 0.5,
    lasso_penalty = "min",
    partition = "kfold",
    val_split = 30,
    cv_folds = 5,
    cv_repeats = 3,
    show_formula = TRUE,
    show_roc = FALSE,
    roc_x = "1spec",
    roc_unit = "percent",
    palBrewer = "Dark2",
    seed = 42) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("mLR requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dep)) dep <- jmvcore::resolveQuo(jmvcore::enquo(dep))
    if ( ! missing(covs)) covs <- jmvcore::resolveQuo(jmvcore::enquo(covs))
    if ( ! missing(factors)) factors <- jmvcore::resolveQuo(jmvcore::enquo(factors))
    if ( ! missing(group)) group <- jmvcore::resolveQuo(jmvcore::enquo(group))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dep), dep, NULL),
            `if`( ! missing(covs), covs, NULL),
            `if`( ! missing(factors), factors, NULL),
            `if`( ! missing(group), group, NULL))

    for (v in dep) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in factors) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in group) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- mLROptions$new(
        dep = dep,
        covs = covs,
        factors = factors,
        group = group,
        selgroup = selgroup,
        method = method,
        elastic_alpha = elastic_alpha,
        lasso_penalty = lasso_penalty,
        partition = partition,
        val_split = val_split,
        cv_folds = cv_folds,
        cv_repeats = cv_repeats,
        show_formula = show_formula,
        show_roc = show_roc,
        roc_x = roc_x,
        roc_unit = roc_unit,
        palBrewer = palBrewer,
        seed = seed)

    analysis <- mLRClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

